      failMutation('POST', '/copy', 409, 'already exists');
      vi.spyOn(window, 'prompt').mockReturnValue('/docs/a.txt');

      buttonsByText(actions, 'Copy')[0].click();
      await flush();

      expect(status.textContent).toBe('Error: 409: already exists');
    });

